const http = require('http');

const server = http.createServer(function(req, res) {
  res.writeHead(200, {'Content-Type': 'text/html'});

  // Basic routing using req.url
  if (req.url === '/') {
    res.end('<h1>Welcome to the Home Page!</h1>');
  } else if (req.url === '/about') {
    res.end('<h1>About Us</h1><p>This is the About page.</p>');
  } else {
    res.writeHead(404);
    res.end('<h1>404 - Page Not Found</h1>');
  }
});

server.listen(3000, function() {
  console.log('Server running at http://localhost:3000');
});

// Explanation:
// req.url contains the path portion of the URL requested by the client.
// For http://localhost:3000/ => req.url = '/'
// For http://localhost:3000/about => req.url = '/about'
// The if-else ladder checks req.url and sends the appropriate response.
// This is called 'basic routing' - directing requests to appropriate handlers.

const http = require(' http ');
const url = require('url');

const server = http.createServer(function(req, res) {
  res.writeHead(200, {'Content-Type': 'text/html'});

  // Parse the URL with query parsing enabled (true)
  const parsedUrl = url.parse(req.url, true);
  const query = parsedUrl.query;

  let response = '<h2>URL Information</h2>';
  response += '<p><b>Pathname:</b> ' + parsedUrl.pathname + '</p>';
  response += '<p><b>Query Parameters:</b></p><ul>';

  for (let key in query) {
    response += '<li>' + key + ' = ' + query[key] + '</li>';
  }
  response += '</ul>';

  res.end(response);
});

server.listen(3000, function() {
  console.log('Server at http://localhost:3000');
  console.log('Try: http://localhost:3000/?name=John&age=25');
});

