// Importance of JSON in web applications:
// 1. Language-independent: Works with any programming language
// 2. Lightweight: Less overhead compared to XML
// 3. Easy parsing: JSON.parse() and JSON.stringify() are simple
// 4. Standard for REST APIs: Most APIs use JSON format
// 5. Browser support: JavaScript natively understands JSON
// 6. Human-readable: Easy to read and debug

const http = require('http');
const url = require('url');
const fs = require('fs');

const server = http.createServer((req, res) => {
  // Parse the URL (true enables query string parsing)
  const parsedUrl = url.parse(req.url, true);
  const queryObject = parsedUrl.query;
  const queryString = JSON.stringify(queryObject);

  // Print query string on console
  console.log('Query String:', queryObject);

  // Write query string to file
  fs.writeFile('querylog.txt', queryString, (err) => {
    if (err) {
      console.error('Error writing to file:', err);
    } else {
      console.log('Query string saved to querylog.txt');
    }
  });

  res.writeHead(200, {'Content-Type': 'application/json'});
  res.end(queryString);
});

